-- CREATE TABLE PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.BENEFIT_COMPONENT_TYPE_MASTER (
--     ID NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
--     CODE VARCHAR2(50) NOT NULL UNIQUE,
--     NAME VARCHAR2(150) NOT NULL,
--     IS_ACTIVE CHAR(1) DEFAULT 'Y' CHECK (IS_ACTIVE IN ('Y','N')),
--     CREATED_AT TIMESTAMP DEFAULT SYSTIMESTAMP,
--     CREATED_BY VARCHAR2(100),
--     UPDATED_AT TIMESTAMP DEFAULT SYSTIMESTAMP,
--     UPDATED_BY VARCHAR2(100)
-- );

-- CREATE TABLE PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.BENEFIT_COMPONENT_TYPE_DETAIL (
--     ID NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
--     BENEFIT_COMPONENT_TYPE_ID NUMBER NOT NULL,
--     COMPONENT_ID NUMBER NOT NULL,
--     IS_ACTIVE CHAR(1) DEFAULT 'Y' CHECK (IS_ACTIVE IN ('Y','N')),
--     CONSTRAINT FK_BENEFIT_TYPE
--         FOREIGN KEY (BENEFIT_COMPONENT_TYPE_ID)
--         REFERENCES BENEFIT_COMPONENT_TYPE_MASTER(ID),
--     CONSTRAINT FK_COMPONENT
--         FOREIGN KEY (COMPONENT_ID)
--         REFERENCES CLAIM_COMPONENT_MASTER(ID)
-- );



MERGE INTO BENEFIT_COMPONENT_TYPE_MASTER t
USING (
    SELECT 'PF_MEMBER' CODE, 'PF Member' NAME FROM DUAL
    UNION ALL
    SELECT 'PF_MEMBER_WITH_INTEREST', 'PF Member + Interest' FROM DUAL
    UNION ALL
    SELECT 'PF_EMPLOYER', 'PF Employer' FROM DUAL
    UNION ALL
    SELECT 'PF_EMPLOYER_WITH_INTEREST', 'PF Employer + Interest' FROM DUAL
    UNION ALL
    SELECT 'VOLUNTARY', 'Voluntary' FROM DUAL
    UNION ALL
    SELECT 'VOLUNTARY_WITH_INTEREST', 'Voluntary + Interest' FROM DUAL
    UNION ALL
    SELECT 'GOVERNMENT', 'Government' FROM DUAL
    UNION ALL
    SELECT 'GOVERNMENT_WITH_INTEREST', 'Government + Interest' FROM DUAL
    UNION ALL
    SELECT 'PENSION_MEMBER', 'Pension Member' FROM DUAL
    UNION ALL
    SELECT 'PENSION_MEMBER_WITH_INTEREST', 'Pension Member + Interest' FROM DUAL
    UNION ALL
    SELECT 'PENSION_EMPLOYER', 'Pension Employer' FROM DUAL
    UNION ALL
    SELECT 'PENSION_EMPLOYER_WITH_INTEREST', 'Pension Employer + Interest' FROM DUAL
    UNION ALL
    SELECT 'LUMPSUM', 'Lumpsum' FROM DUAL
    UNION ALL
    SELECT 'LAPSE_TERMINATION', 'Lapse (Termination)' FROM DUAL
    UNION ALL
    SELECT 'WR_WITH_INTEREST', 'Wrong Remittance with Interest' FROM DUAL
    UNION ALL
    SELECT 'WR_WITHOUT_INTEREST', 'Wrong Remittance without Interest' FROM DUAL
) src
ON (t.CODE = src.CODE)
WHEN NOT MATCHED THEN
    INSERT (CODE, NAME, CREATED_BY)
    VALUES (src.CODE, src.NAME, 'SYSTEM');

GRANT REFERENCES ON PPFMS_CONTRIBUTIONS_PAYMENTS_SERVICE_SCHEMA.COMPONENT_MASTER
TO PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA;

CREATE TABLE PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.BENEFIT_COMPONENT_TYPE_DETAIL (

    ID NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,

    BENEFIT_COMPONENT_TYPE_ID NUMBER NOT NULL,

    COMPONENT_ID NUMBER NOT NULL,

    IS_ACTIVE CHAR(1) DEFAULT 'Y' CHECK (IS_ACTIVE IN ('Y','N')),

    CONSTRAINT FK_BENEFIT_TYPE
        FOREIGN KEY (BENEFIT_COMPONENT_TYPE_ID)
        REFERENCES BENEFIT_COMPONENT_TYPE_MASTER(ID),

    CONSTRAINT FK_COMPONENT
        FOREIGN KEY (COMPONENT_ID)
        REFERENCES PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.COMPONENT_MASTER(ID)
);

INSERT INTO PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.BENEFIT_COMPONENT_TYPE_DETAIL
(BENEFIT_COMPONENT_TYPE_ID, COMPONENT_ID)
SELECT t.ID, c.ID
FROM PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.BENEFIT_COMPONENT_TYPE_MASTER t
JOIN PPFMS_CONTRIBUTIONS_PAYMENTS_SERVICE_SCHEMA.COMPONENT_MASTER c
  ON c.CODE IN ('PF_MC', 'PF_IMC')
WHERE t.CODE = 'PF_MEMBER_WITH_INTEREST';

