SELECT t.ID, c.ID
FROM PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.BENEFIT_COMPONENT_TYPE_MASTER t
JOIN PPFMS_CONTRIBUTIONS_PAYMENTS_SERVICE_SCHEMA.COMPONENT_MASTER c
  ON c.CODE IN ('PC_EC', 'PC_IEC')
WHERE t.CODE = 'PENSION_EMPLOYER_WITH_INTEREST';

