------------------------------------------------------------

-- 1) TERM_BEFORE_2013_GT_12
-- Payable/eligibility side from document:
-- PF_MC + PF_IMC
INSERT INTO PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.CLAIM_ELIGIBILITY_COMPONENT_MAP
(RULE_ID, BENEFIT_COMPONENT_TYPE_ID)
SELECT r.ID, b.ID
FROM PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.CLAIM_ELIGIBILITY_MASTER r
JOIN PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.BENEFIT_COMPONENT_TYPE_MASTER b
  ON b.CODE = 'PF_MEMBER_WITH_INTEREST'
WHERE r.RULE_CODE = 'TERM_BEFORE_2013_GT_12'
  AND NOT EXISTS (
      SELECT 1
      FROM PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.CLAIM_ELIGIBILITY_COMPONENT_MAP m
      WHERE m.RULE_ID = r.ID
        AND m.BENEFIT_COMPONENT_TYPE_ID = b.ID
  );

