  ON b.CODE IN (
      'PF_MEMBER_WITH_INTEREST',
      'PF_EMPLOYER_WITH_INTEREST',
      'PENSION_MEMBER_WITH_INTEREST',
      'PENSION_EMPLOYER_WITH_INTEREST'
  )
WHERE r.RULE_CODE = 'NORMAL_GT_12_SIM'
  AND NOT EXISTS (
      SELECT 1
      FROM PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.CLAIM_ELIGIBILITY_COMPONENT_MAP m
      WHERE m.RULE_ID = r.ID
        AND m.BENEFIT_COMPONENT_TYPE_ID = b.ID
