WHERE r.RULE_CODE = 'NORMAL_LT_12_TIER2'
  AND NOT EXISTS (
      SELECT 1
      FROM PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.CLAIM_ELIGIBILITY_COMPONENT_MAP m
      WHERE m.RULE_ID = r.ID
        AND m.BENEFIT_COMPONENT_TYPE_ID = b.ID
  );

COMMIT;
-- note for the claim eligibility
CLAIM_ELIGIBILITY_MASTER        → WHEN rule applies
CLAIM_ELIGIBILITY_CATEGORY_MAP  → WHO it applies to
CLAIM_ELIGIBILITY_COMPONENT_MAP → WHAT is paid

BENEFIT_COMPONENT_TYPE_MASTER   → business group
BENEFIT_COMPONENT_TYPE_DETAIL   → expands to raw components
CLAIM_COMPONENT_MASTER          → actual money components

