-- CREATE TABLE PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.INTEREST_METHOD_MASTER (
--     ID NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
--     CODE VARCHAR2(50) NOT NULL UNIQUE,
--     NAME VARCHAR2(100) NOT NULL,
--     DESCRIPTION VARCHAR2(255),
--     IS_ACTIVE CHAR(1) DEFAULT 'Y'
--         CHECK (IS_ACTIVE IN ('Y','N')),
--     CREATED_AT TIMESTAMP DEFAULT SYSTIMESTAMP,
--     CREATED_BY VARCHAR2(100),
--     UPDATED_AT TIMESTAMP DEFAULT SYSTIMESTAMP,
--     UPDATED_BY VARCHAR2(100)
-- );



MERGE INTO PPFMS_CLAIMS_WORKFLOW_SERVICE_SCHEMA.INTEREST_METHOD_MASTER t
USING (
    SELECT 'NORMAL' AS CODE, 'Normal Interest' AS NAME, 'Standard interest treatment from contribution engine' AS DESCRIPTION FROM DUAL
    UNION ALL SELECT 'WITH_INTEREST', 'With Interest', 'Refund/payment includes interest' FROM DUAL
    UNION ALL SELECT 'WITHOUT_INTEREST', 'Without Interest', 'Refund/payment excludes interest' FROM DUAL
    UNION ALL SELECT 'BACKDATED', 'Backdated Interest', 'Interest calculated up to backdated processed/refund date' FROM DUAL
    UNION ALL SELECT 'FREEZE', 'Freeze Interest', 'Interest frozen as per policy/configuration' FROM DUAL
    UNION ALL SELECT 'MANUAL_OVERRIDE', 'Manual Override', 'Interest handled manually by authorized user' FROM DUAL
) src
ON (t.CODE = src.CODE)

WHEN NOT MATCHED THEN
INSERT (CODE, NAME, DESCRIPTION, CREATED_BY)
VALUES (src.CODE, src.NAME, src.DESCRIPTION, 'SYSTEM');